var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"......결국 져 버렸네.","JPN":"……結局負けてしまったね。","ENG":"...We lost in the end.","TWN":"……最後還是輸了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"하지만 살아 있어서 다행이야.","JPN":"でも生きていてよかった。","ENG":"But I'm glad I'm alive.","TWN":"不過幸好還活著。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그 마술사 선배가 무서운 얼굴로 공을 내려칠 때는 정말 죽는 줄 알았다니까.","JPN":"あのマジシャン先輩が恐ろしい顔でボールを打ち下ろす時はガチで死ぬかと思ったよ。","ENG":"When that magician senior smashed the ball with fury in her eyes, I thought I was going to die.","TWN":"那個魔術師前輩用可怕的表情擊球時，我真的以為自己要死了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"대체 어떤 원리로 공을 별처럼 빛나게 하는 걸까? 궁금하지 않아?","JPN":"いったいどんな原理でボールを星みたいに輝かせたのだろう？　気にならない？","ENG":"And by the way, what makes the ball shine like a star? I want to know how it works!","TWN":"究竟是用什麼原理讓球像星星一樣發光的呢？你們不好奇嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"왜 그래, 케이시?","JPN":"どうしたんだい、ケイシー？","ENG":"What's wrong, Kaci?","TWN":"怎麼了，卡西？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"설마 진 것 때문에 그래? 겨우 한 경기잖아?","JPN":"まさか負けたから？　たったの1試合だよ？","ENG":"Are you upset because we lost? Come on, it's only one game!","TWN":"難道是因為輸了比賽？才一場比賽而已。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"하지만...... 이제 마지막 경기만 남았잖아.","JPN":"でも……もう最後の試合しか残っていない。","ENG":"But... Now we have only one game.","TWN":"可是……現在只剩下最後一場比賽了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"만약 소원구슬을 못 얻으면 어떡해?","JPN":"もし願い玉をもらえなかったらどうしよう？","ENG":"What if we don't get the Wishing Ball?","TWN":"萬一拿不到許願珠怎麼辦？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"소원구슬이 없으면...... 우린 또 스카이를 잊어버릴지도 모르잖아......","JPN":"願い玉がないと……あたしたちはまたスカイのことを忘れてしまうかもしれない……","ENG":"Without the Wishing Ball... we might forget about Sky again...","TWN":"沒有許願珠的話……說不定我們也很快就會忘掉絲凱的……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"괜찮아, 케이시!","JPN":"大丈夫だよ、ケイシー！","ENG":"It's okay, Kaci!","TWN":"沒關係，卡西！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"케이시랑 아르티가 날 잊어버려도 기다릴 수 있어. 우린 이미 친구잖아.","JPN":"ケイシーとアルティが私を忘れても待つことができる。私たちはもう友達でしょ？","ENG":"I can wait, even if you don't remember me. We're friends.","TWN":"就算卡西和阿爾蒂忘了我，我也會等著的，我們是朋友不是嗎。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"난 싫어!","JPN":"あたしは嫌なの！","ENG":"No, it's not okay!","TWN":"我不要！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"난...... 스카이 널 잊어버리기 싫단 말이야.","JPN":"あたしは……スカイ、君を忘れたくないの。","ENG":"I... I don't want to forget you, Sky.","TWN":"我……不要忘了絲凱。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"미, 미안......","JPN":"ご、ごめん……","ENG":"S-sorry...","TWN":"對，對不起……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"아까 양호실에서 깨어났을 때......","JPN":"さっき保健室で目覚めた時……","ENG":"When I woke up in the infirmary earlier...","TWN":"剛剛在保健室醒來時……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이를 잊어버린 아르티를 보고 무서워졌어.","JPN":"スカイのことを忘れてしまったアルティを見て怖くなったの。","ENG":"I got scared when I realized Arti didn't remember you.","TWN":"看到忘了你的阿爾蒂，我很害怕。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"나도...... 그렇게 잊어버릴까 봐.","JPN":"あたしも……そうやって忘れてしまうのが。","ENG":"I was afraid... I might forget you too.","TWN":"我怕……自己也那樣忘了你。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"그래서, 싫어도 꾹 참고 싸운 건데......","JPN":"だから、嫌でもぐっと我慢して戦ったのに……","ENG":"So I fought hard, even though I didn't want to...","TWN":"所以，我才會明明很討厭也堅持比賽……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이는 어째서 아무렇지도 않은 거야?","JPN":"スカイはどうして平気なの？","ENG":"How can you say that, like it's nothing?","TWN":"絲凱你怎麼能那麼若無其事的呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"케, 케이시...... 많이 화났어?","JPN":"ケ、ケイシー……怒っちゃった？","ENG":"K-Kaci... Are you mad at me?","TWN":"卡，卡西……你生氣了？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"나이엘 선배를 응원 안 했으면 피구도 이겼을 거야.","JPN":"ナイエル先輩を応援しなかったら、ドッジボールも勝てたと思う。","ENG":"If you hadn't cheered for Naielle, we would have won that game too.","TWN":"如果你不給奈爾前輩加油，躲避球比賽我們也能贏的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"왜 스카이가 선배를 응원했는지...... 난 모르겠어.","JPN":"なぜスカイが先輩を応援したのか……あたしにはわからない。","ENG":"I really don't understand... why you did that...","TWN":"我不明白……絲凱你為什麼要給前輩加油。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"케이시...... 나, 난 그냥......","JPN":"ケイシー……わ、私はただ……","ENG":"Kaci... I-I just...","TWN":"卡西……，我，我只是……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"나도 모르겠어...... 미안해......","JPN":"私もよくわからない……ごめんね……","ENG":"I don't know why I did... I’m so sorry.","TWN":"我也不知道……對不起……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"바보......","JPN":"バカ……","ENG":"Fool...","TWN":"笨蛋……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"스카이는 바보야!","JPN":"スカイのバカ！","ENG":"You're a fool, Sky!","TWN":"絲凱是笨蛋！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"앗?! 케이시!","JPN":"あっ！？　ケイシー！","ENG":"Ah? Kaci!","TWN":"啊？！卡西！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"어라? 이런 반응까지는 예상 못 했는데?","JPN":"あれ？　こういう反応は予想できなかったな。","ENG":"Hmm? I didn't expect this.","TWN":"哎喲？沒想到她會是這種反應。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"케이시가 화를 냈어...... 저런 모습은 처음 봐......","JPN":"ケイシーが怒っている……あんな姿は初めてみた……","ENG":"Kaci actually lost her temper... I've never seen her like that...","TWN":"卡西生氣了……我還是頭一次看到她這個樣子……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"자, 자. 너무 기죽지 마. 좀 있으면 화내서 미안하다고 돌아올 테니까.","JPN":"まあまあ、あまり落ち込まないで。少ししたら怒ってごめんねって言いながら帰ってくるから。","ENG":"There, there. Don't worry too much. Soon she'll come back and apologize.","TWN":"好了，好了，別垂頭喪氣的了，等一下她就該回來跟你道歉，說自己不該發火了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"그치만...... 저렇게까지 화를 냈는데?","JPN":"でも……あそこまで怒ってたし……","ENG":"But... She's so upset.","TWN":"可是……她發了那麼大的脾氣。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"다시 안 만나려고 하면 어떡해. 그러다 그대로 날 잊어버리면......","JPN":"二度と会いたくないって言われたらどうしよう。それでそのまま私のことを忘れたら……","ENG":"What if she doesn't want to see me again? And then forgets about me... just like that...","TWN":"她要是再也不想見我了怎麼辦？就那樣忘了我該怎麼辦……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"한 번 싸운다고 헤어지는 건 친구가 아냐, 더듬이.","JPN":"1回ケンカしたからって絶交するのは友達じゃないさ、アホ毛ちゃん。","ENG":"Having a quarrel doesn't mean the end of friendship, Antenna.","TWN":"吵一次架就分開的朋友根本就不是朋友，小觸角。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그리고 케이시가 널 싫어할 리 없어. 오히려 아주 좋아할걸?","JPN":"そしてケイシーが君を嫌いなはずがない。むしろすごく気に入っているよ？","ENG":"Besides, Kaci doesn't hate you. On the contrary, I bet she likes you a lot.","TWN":"而且卡西不可能會討厭你，相反她還很喜歡你呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"정말? 혼자 가 버렸는데도......?","JPN":"本当に？　一人で行っちゃったのに……？","ENG":"Really? Even though she just left like that?","TWN":"真的嗎？她都一個人走掉了……？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"당연하지. 아카데미에서 나보다 케이시에 대해 잘 아는 사람은 없거든.","JPN":"当然さ。このアカデミーでぼくよりケイシーのことに詳しい人はいないからね。","ENG":"Of course. No one in the Academy knows more about Kaci than me.","TWN":"當然了，學院裡再沒有比我更瞭解卡西的人了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"케이시가 겉으로는 식물밖에 모르는 바보 같지만, 속은 그렇지 않아.","JPN":"ケイシーは傍から見ればただの植物オタクにみえるかもしれないけど、中身はそうじゃない。","ENG":"She looks like a fool who doesn't know about anything but plants, but she's not.","TWN":"卡西外表看起來像是個只知道植物的笨蛋，其實內心根本不是那樣的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"내가 아는 아카데미 학생들 중에서 제일 강하고, 정이 많은 애거든.","JPN":"ぼくの知っているアカデミーの生徒の中で、一番強くて情に厚い子なのさ。","ENG":"She's the strongest and kindest student I know.","TWN":"她是我認識的學院學生裡面最強大，最重情義的人。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"친구의 말실수 정도는 충분히 이해해 줄 수 있을 만큼 말이야.","JPN":"友達の失言くらいは十分理解してあげられるぐらいね。","ENG":"She'll understand, even if you make a mistake or two.","TWN":"朋友不小心說錯話了，她一定會理解的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"아르티는...... 케이시에 대해 어떻게 그렇게 잘 알아?","JPN":"アルティは……なんでケイシーについてそんなに詳しいの？","ENG":"Arti... How do you know Kaci so well?","TWN":"阿爾蒂……你怎麼會那麼瞭解卡西呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그야 꽃꽂이부가 폐부됐을 때 내가 직접 케이시를 우리 동아리로 불러왔거든.","JPN":"それは、華道部が廃部になった時、ぼくが直接ケイシーをうちのサークルに誘ったんだ。","ENG":"Because I was the one who invited her to our club when the flower arranging club was closed.","TWN":"那是因為插花部關掉時，我親自把卡西招來了我們社團。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그 애의 엄청난 괴력을 가까이에서 관찰해 보고 싶었으니까.","JPN":"あの子のものすごい怪力を近くで観察したかったから。","ENG":"I wanted to watch her superhuman strength closely.","TWN":"因為我想近距離地觀察她那非同尋常的怪力。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"처음에는 망설였는데 꽃꽂이는 우리 동아리에서도 계속 할 수 있다고 하니까 승낙하더라.","JPN":"最初はためらっていたけど、生け花はうちのサークルでも続けられると説得したら承諾してくれたよ。","ENG":"She hesitated at first, but when I told her that she could continue to do flower arranging in our club, she agreed.","TWN":"一開始她很猶豫，後來我說在我們社團也可以繼續插花，她才同意的。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"같은 부실에 있으면서 얘기도 많이 나누고, 그러니 잘 알게 될 수밖에.","JPN":"同じ部室にいる時おしゃべりもたくさんしたから、そのうちあの子のことを知り尽くしたっていうか。","ENG":"Since there were only two of us, we talked a lot in the club room. Eventually, we got to know each other very well.","TWN":"在同一個社團活動室裡，我們經常一起聊天，自然而然地就很瞭解對方了。"},"stage":{"bg":"LIBRARY_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까 내 말을 믿어. 별로 논리적으로 들리진 않겠지만.","JPN":"だからぼくの話を信じていいよ。別に論理的な話には聞こえないかもだけど。","ENG":"So trust my words on this. Though it may not sound logical.","TWN":"所以，你相信我，雖然我的話聽起來沒什麼邏輯性。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"케이시가...... 날 다시 친구로 받아들여 줄까?","JPN":"ケイシーは……また私を友達として受け入れてくれるかな？","ENG":"Will Kaci... accept me as her friend again?","TWN":"卡西……還會重新接受我做朋友嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"에이, 애초에 친구가 아니었던 적은 한 번도 없었다니까.","JPN":"いや、そもそも友達じゃなかった時は一度もなかったって。","ENG":"Come on, you never stopped being her friend.","TWN":"哎呀，她從頭至尾也沒說你不是她的朋友呀。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"정 사과하고 싶으면 선물이라도 준비해 둬. 케이시는 꽃을 좋아하거든.","JPN":"本当に謝りたいならプレゼントでも用意しておけば？　ケイシーはお花が好きなんだ。","ENG":"If you really want to apologize, then give her a present or something. Kaci likes flowers.","TWN":"你真想道歉的話，就給她準備個禮物。卡西很喜歡花。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그러니까...... 이름이......?","JPN":"で、君の名前って……","ENG":"So, uh... What was your name again?","TWN":"所以……你叫……？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"RULER_JUNIOR_SPORTS_NULL","text":{"KOREA":"스카이.","JPN":"スカイ。","ENG":"Sky.","TWN":"絲凱。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_NULL","text":{"KOREA":"그래, 더듬이!","JPN":"……そう、アホ毛！","ENG":"Right, Antenna!","TWN":"好的，小觸角！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAKER_JUNIOR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RULER_JUNIOR_SPORTS_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};